#!/usr/bin/env perl

use strict;
use warnings;
use JSON;
use Scalar::Util qw(blessed);

my $config_file = 'validation_config.json';
my %patterns;

sub load_config {
    my ($file) = @_;
    if (-e $file) {
        open my $fh, '<', $file or die "Cannot open config file: $!";
        local $/;
        my $json = <$fh>;
        close $fh;
        my $config = decode_json($json);
        return %{$config->{patterns}} if $config->{patterns};
    }
    return ();
}

sub save_pattern {
    my ($name, $pattern) = @_;
    $patterns{$name} = $pattern;
    my $config = { patterns => \%patterns };
    open my $fh, '>', $config_file or die "Cannot write config file: $!";
    print $fh encode_json($config);
    close $fh;
}

sub compile_pattern {
    my ($pattern) = @_;
    my $compiled;
    eval {
        $compiled = qr/$pattern/;
    };
    if ($@) {
        die "Invalid regex pattern: $@";
    }
    return $compiled;
}

sub validate_string {
    my ($string, $pattern) = @_;
    my $compiled = ref($pattern) eq 'Regexp' ? $pattern : compile_pattern($pattern);
    return $string =~ /$compiled/;
}

sub validate_with_named_pattern {
    my ($string, $pattern_name) = @_;
    die "Pattern '$pattern_name' not found" unless exists $patterns{$pattern_name};
    return validate_string($string, $patterns{$pattern_name});
}

sub add_pattern_interactive {
    print "Enter pattern name: ";
    chomp(my $name = <STDIN>);
    print "Enter regex pattern: ";
    chomp(my $pattern = <STDIN>);
    
    eval {
        compile_pattern($pattern);
    };
    if ($@) {
        print "Error: Invalid pattern - $@\n";
