    save_pattern($name, $pattern);
    print "Pattern '$name' saved successfully\n";
}

sub test_pattern_interactive {
    print "Enter pattern name or regex: ";
    chomp(my $input = <STDIN>);
    
    my $pattern;
    if (exists $patterns{$input}) {
        $pattern = $patterns{$input};
        print "Using saved pattern: $pattern\n";
    } else {
        $pattern = $input;
    }
    
    print "Enter test string: ";
    chomp(my $test_string = <STDIN>);
    
    eval {
        my $result = validate_string($test_string, $pattern);
        if ($result) {
            print "MATCH: String matches pattern\n";
        } else {
            print "NO MATCH: String does not match pattern\n";
        }
    };
    if ($@) {
        print "Error: $@\n";
    }
}

sub list_patterns {
    if (keys %patterns) {
        print "\nSaved patterns:\n";
        foreach my $name (sort keys %patterns) {
            print "  $name: $patterns{$name}\n";
        }
    } else {
        print "No saved patterns\n";
    }
}

sub batch_validate {
    print "Enter pattern name or regex: ";
    chomp(my $input = <STDIN>);
    
    my $pattern;
    if (exists $patterns{$input}) {
        $pattern = $patterns{$input};
    } else {
        $pattern = $input;
    }
    
    my $compiled;
    eval {
        $compiled = compile_pattern($pattern);
    };
    if ($@) {
        print "Error: $@\n";
        return;
    }
    
    print "Enter test strings (one per line, empty line to finish):\n";
    my @results;
    while (my $line = <STDIN>) {
        chomp $line;
        last if $line eq '';
        
        my $match = validate_string($line, $compiled);
        push @results, {
            string => $line,
            match => $match
        };
    }
    
    print "\nResults:\n";
    foreach my $result (@results) {
        my $status = $result->{match} ? 'MATCH' : 'NO MATCH';
        print "  [$status] $result->{string}\n";
    }
}

sub validate_from_user_input {
    my ($test_string, $user_pattern) = @_;
    
    my $result;
    eval {
        my $compiled = qr/$user_pattern/;
        $result = $test_string =~ /$compiled/;
    };
    
    if ($@) {
        return { error => "Pattern compilation failed: $@" };
    }
    
    return { match => $result };
}

sub advanced_validation {
    print "Enter pattern with modifiers (e.g., /pattern/i): ";
    chomp(my $input = <STDIN>);
    
    my ($pattern, $modifiers) = ('', '');
    if ($input =~ m{^/(.+?)/([imsxadlu]*)$}) {
        $pattern = $1;
        $modifiers = $2 || '';
